package com.example.safeway

import android.Manifest
import android.content.pm.PackageManager
import android.os.Build
import android.os.Bundle
import android.telephony.SmsManager
import android.widget.FrameLayout
import android.widget.ImageButton
import android.widget.LinearLayout
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.core.app.ActivityCompat
import androidx.core.content.ContextCompat
import androidx.lifecycle.lifecycleScope
import com.example.safeway.data.AppDatabase
import com.google.android.material.chip.Chip
import kotlinx.coroutines.launch
import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale

class EmergencyAlertActivity : AppCompatActivity() {

    private lateinit var btnBack: ImageButton
    private lateinit var btnSendSOS: FrameLayout
    private lateinit var llContactsList: LinearLayout
    private lateinit var tvSMSPreview: TextView
    private lateinit var tvLocationName: TextView
    private lateinit var tvLocationCoords: TextView
    private lateinit var database: AppDatabase

    companion object {
        private const val SMS_PERMISSION_REQUEST_CODE = 1001
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_emergency_alert)

        database = AppDatabase.getDatabase(this)

        initializeViews()
        setupListeners()
        loadContacts()
    }

    private fun initializeViews() {
        btnBack = findViewById(R.id.btn_back_sos)
        btnSendSOS = findViewById(R.id.btn_send_sos)
        llContactsList = findViewById(R.id.ll_contacts_list)
        tvSMSPreview = findViewById(R.id.tv_sms_preview)
        tvLocationName = findViewById(R.id.tv_location_name)
        tvLocationCoords = findViewById(R.id.tv_location_coords)
    }

    private fun setupListeners() {
        btnBack.setOnClickListener {
            finish()
        }

        btnSendSOS.setOnClickListener {
            if (hasSmsPermission()) {
                sendEmergencyAlert()
            } else {
                requestSmsPermission()
            }
        }
    }

    private fun loadContacts() {
        lifecycleScope.launch {
            try {
                val contacts = database.contactDao().getContactsWithSmsAlerts()
                displayContacts(contacts)
                updateSmsPreview()
            } catch (e: Exception) {
                Toast.makeText(this@EmergencyAlertActivity, "Error loading contacts", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun displayContacts(contacts: List<com.example.safeway.data.Contact>) {
        llContactsList.removeAllViews()

        if (contacts.isEmpty()) {
            val emptyText = TextView(this).apply {
                text = "No contacts with SMS alerts enabled"
                setTextColor(ContextCompat.getColor(this@EmergencyAlertActivity, R.color.neutral_muted))
                textSize = 12f
                setPadding(16, 16, 16, 16)
            }
            llContactsList.addView(emptyText)
            return
        }

        contacts.forEach { contact ->
            val chip = Chip(this).apply {
                text = contact.name
                isClickable = false
                isCheckable = false
                chipBackgroundColor = ContextCompat.getColorStateList(
                    this@EmergencyAlertActivity,
                    R.color.card_background
                )
                setTextColor(ContextCompat.getColor(this@EmergencyAlertActivity, R.color.text_primary))
                chipStrokeWidth = 1f
                chipStrokeColor = ContextCompat.getColorStateList(
                    this@EmergencyAlertActivity,
                    R.color.border_dark
                )
                chipCornerRadius = 28f
                textSize = 12f
                setEnsureMinTouchTargetSize(false)
            }

            val params = LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.WRAP_CONTENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                rightMargin = 8
                bottomMargin = 8
            }

            chip.layoutParams = params
            llContactsList.addView(chip)
        }
    }

    private fun updateSmsPreview() {
        tvSMSPreview.text = buildAlertMessage()
    }

    private fun buildAlertMessage(): String {
        val timestamp = SimpleDateFormat("hh:mm:ss a", Locale.getDefault()).format(Date())
        val locationText = tvLocationCoords.text.toString().replace(" • live", "")

        return "SHIELD ALERT: Thomas needs help. Location: $locationText. Time: $timestamp. Automated safety alert."
    }

    private fun sendEmergencyAlert() {
        lifecycleScope.launch {
            try {
                val contacts = database.contactDao().getContactsWithSmsAlerts()

                if (contacts.isEmpty()) {
                    Toast.makeText(
                        this@EmergencyAlertActivity,
                        "No contacts with SMS alerts enabled",
                        Toast.LENGTH_SHORT
                    ).show()
                    return@launch
                }

                val message = buildAlertMessage()
                tvSMSPreview.text = message

                val smsManager = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                    getSystemService(SmsManager::class.java)
                } else {
                    @Suppress("DEPRECATION")
                    SmsManager.getDefault()
                }

                var successCount = 0
                contacts.forEach { contact ->
                    try {
                        smsManager.sendTextMessage(
                            contact.phone,
                            null,
                            message,
                            null,
                            null
                        )
                        successCount++
                    } catch (e: Exception) {
                        e.printStackTrace()
                    }
                }

                Toast.makeText(
                    this@EmergencyAlertActivity,
                    "Emergency alert sent to $successCount contact(s)",
                    Toast.LENGTH_LONG
                ).show()

            } catch (e: Exception) {
                Toast.makeText(
                    this@EmergencyAlertActivity,
                    "Failed to send SMS: ${e.message}",
                    Toast.LENGTH_LONG
                ).show()
            }
        }
    }

    private fun hasSmsPermission(): Boolean {
        return ContextCompat.checkSelfPermission(
            this,
            Manifest.permission.SEND_SMS
        ) == PackageManager.PERMISSION_GRANTED
    }

    private fun requestSmsPermission() {
        ActivityCompat.requestPermissions(
            this,
            arrayOf(Manifest.permission.SEND_SMS),
            SMS_PERMISSION_REQUEST_CODE
        )
    }

    override fun onRequestPermissionsResult(
        requestCode: Int,
        permissions: Array<out String>,
        grantResults: IntArray
    ) {
        super.onRequestPermissionsResult(requestCode, permissions, grantResults)

        if (requestCode == SMS_PERMISSION_REQUEST_CODE) {
            if (grantResults.isNotEmpty() && grantResults[0] == PackageManager.PERMISSION_GRANTED) {
                sendEmergencyAlert()
            } else {
                Toast.makeText(
                    this,
                    "SMS permission is required to send an emergency alert",
                    Toast.LENGTH_LONG
                ).show()
            }
        }
    }
}

package com.example.safeway

import android.app.AlertDialog
import android.os.Bundle
import android.view.LayoutInflater
import android.widget.*
import androidx.appcompat.app.AppCompatActivity
import androidx.core.content.ContextCompat
import androidx.lifecycle.lifecycleScope
import com.example.safeway.data.AppDatabase
import com.example.safeway.data.Contact
import kotlinx.coroutines.launch

class SupportCircleActivity : AppCompatActivity() {

    private lateinit var btnBack: ImageButton
    private lateinit var btnAddContact: LinearLayout
    private lateinit var contactsContainer: LinearLayout
    private lateinit var database: AppDatabase

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_support_circle)

        database = AppDatabase.getDatabase(this)

        initializeViews()
        setupListeners()
        loadContacts()
    }

    override fun onResume() {
        super.onResume()
        loadContacts()
    }

    private fun initializeViews() {
        btnBack = findViewById(R.id.btn_back_circle)
        btnAddContact = findViewById(R.id.btn_add_contact)
        contactsContainer = findViewById(R.id.contacts_container)
    }

    private fun setupListeners() {
        btnBack.setOnClickListener {
            finish()
        }

        btnAddContact.setOnClickListener {
            showAddContactDialog()
        }
    }

    private fun loadContacts() {
        lifecycleScope.launch {
            try {
                val contacts = database.contactDao().getAllContacts()
                displayContacts(contacts)
            } catch (e: Exception) {
                Toast.makeText(this@SupportCircleActivity, "Error loading contacts", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun displayContacts(contacts: List<Contact>) {
        contactsContainer.removeAllViews()

        if (contacts.isEmpty()) {
            val emptyText = TextView(this).apply {
                text = "No trusted contacts added yet. Tap the + button to add one."
                setTextColor(ContextCompat.getColor(this@SupportCircleActivity, R.color.neutral_muted))
                textSize = 12f
                setPadding(16, 16, 16, 16)
            }
            contactsContainer.addView(emptyText)
            return
        }

        contacts.forEach { contact ->
            val card = createContactCard(contact)
            contactsContainer.addView(card)
        }
    }

    private fun createContactCard(contact: Contact): LinearLayout {
        val card = LinearLayout(this).apply {
            orientation = LinearLayout.HORIZONTAL
            setBackgroundResource(R.drawable.card_background)
            setPadding(12, 12, 12, 12)
            layoutParams = LinearLayout.LayoutParams(
                LinearLayout.LayoutParams.MATCH_PARENT,
                LinearLayout.LayoutParams.WRAP_CONTENT
            ).apply {
                bottomMargin = 8
            }
        }

        // Avatar
        val avatar = FrameLayout(this).apply {
            layoutParams = LinearLayout.LayoutParams(42, 42)
            setBackgroundResource(R.drawable.avatar_background)
        }

        val initials = TextView(this).apply {
            text = contact.name.take(2).uppercase()
            textSize = 11f
            gravity = android.view.Gravity.CENTER
            setTextColor(ContextCompat.getColor(this@SupportCircleActivity, R.color.highlight_accent))
        }
        avatar.addView(initials)

        // Info Layout
        val infoLayout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            layoutParams = LinearLayout.LayoutParams(0, LinearLayout.LayoutParams.WRAP_CONTENT, 1f)
            setPadding(12, 0, 0, 0)
        }

        val name = TextView(this).apply {
            text = contact.name
            textSize = 14f
            setTextColor(ContextCompat.getColor(this@SupportCircleActivity, R.color.text_primary))
        }

        val phone = TextView(this).apply {
            text = "${contact.relationship} • ${contact.phone}"
            textSize = 12f
            setTextColor(ContextCompat.getColor(this@SupportCircleActivity, R.color.neutral_muted))
            setPadding(0, 4, 0, 0)
        }

        infoLayout.addView(name)
        infoLayout.addView(phone)

        // Status Layout
        val statusLayout = LinearLayout(this).apply {
            orientation = LinearLayout.VERTICAL
            layoutParams = LinearLayout.LayoutParams(LinearLayout.LayoutParams.WRAP_CONTENT, LinearLayout.LayoutParams.WRAP_CONTENT)
        }

        val statusChip = com.google.android.material.chip.Chip(this).apply {
            text = if (contact.smsAlerts) "SMS alerts" else "Disabled"
            textSize = 10f
            isClickable = false
            isCheckable = false
            chipBackgroundColor = ContextCompat.getColorStateList(
                this@SupportCircleActivity,
                if (contact.smsAlerts) R.color.primary_accent else R.color.card_background
            )
            chipStrokeColor = ContextCompat.getColorStateList(
                this@SupportCircleActivity,
                R.color.border_dark
            )
            chipStrokeWidth = 1f
            chipCornerRadius = 12f
        }

        statusLayout.addView(statusChip)

        // Delete Button
        val deleteBtn = Button(this).apply {
            text = "Remove"
            textSize = 10f
            setOnClickListener {
                AlertDialog.Builder(this@SupportCircleActivity)
                    .setTitle("Remove Contact")
                    .setMessage("Remove ${contact.name} from your support circle?")
                    .setPositiveButton("Remove") { _, _ ->
                        lifecycleScope.launch {
                            database.contactDao().deleteContact(contact)
                            loadContacts()
                        }
                    }
                    .setNegativeButton("Cancel", null)
                    .show()
            }
            layoutParams = LinearLayout.LayoutParams(LinearLayout.LayoutParams.WRAP_CONTENT, LinearLayout.LayoutParams.WRAP_CONTENT)
        }

        card.addView(avatar)
        card.addView(infoLayout)
        card.addView(statusLayout)
        card.addView(deleteBtn)

        return card
    }

    private fun showAddContactDialog() {
        val inflater = LayoutInflater.from(this)
        val view = inflater.inflate(R.layout.dialog_add_contact, null)

        val nameInput = view.findViewById<EditText>(R.id.input_name)
        val phoneInput = view.findViewById<EditText>(R.id.input_phone)
        val relationInput = view.findViewById<EditText>(R.id.input_relationship)
        val smsAlertsCheckbox = view.findViewById<CheckBox>(R.id.checkbox_sms_alerts)

        AlertDialog.Builder(this)
            .setTitle("Add Trusted Contact")
            .setView(view)
            .setPositiveButton("Add") { _, _ ->
                if (nameInput.text.isBlank() || phoneInput.text.isBlank()) {
                    Toast.makeText(this, "Please fill in name and phone", Toast.LENGTH_SHORT).show()
                    return@setPositiveButton
                }

                val contact = Contact(
                    name = nameInput.text.toString(),
                    phone = phoneInput.text.toString(),
                    relationship = relationInput.text.toString().ifBlank { "Friend" },
                    smsAlerts = smsAlertsCheckbox.isChecked
                )

                lifecycleScope.launch {
                    database.contactDao().insertContact(contact)
                    loadContacts()
                    Toast.makeText(this@SupportCircleActivity, "Contact added", Toast.LENGTH_SHORT).show()
                }
            }
            .setNegativeButton("Cancel", null)
            .show()
    }
}

package com.example.safeway.data

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase

@Database(entities = [Contact::class], version = 1, exportSchema = false)
abstract class AppDatabase : RoomDatabase() {

    abstract fun contactDao(): ContactDao

    companion object {
        @Volatile
        private var INSTANCE: AppDatabase? = null

        fun getDatabase(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    "shield_database"
                ).build()
                INSTANCE = instance
                instance
            }
        }
    }
}

package com.example.safeway.data
import androidx.room.Entity import androidx.room.PrimaryKey
@Entity(tableName = "contacts") data class Contact( @PrimaryKey(autoGenerate = true) val id: Int = 0, val name: String, val phone: String, val relationship: String, val smsAlerts: Boolean = true, val includeGPS: Boolean = true )

package com.example.safeway.data

import androidx.room.Dao
import androidx.room.Delete
import androidx.room.Insert
import androidx.room.Query

@Dao
interface ContactDao {

    @Insert
    suspend fun insertContact(contact: Contact)

    @Delete
    suspend fun deleteContact(contact: Contact)

    @Query("SELECT * FROM contacts")
    suspend fun getAllContacts(): List<Contact>

    @Query("SELECT * FROM contacts WHERE id = :contactId")
    suspend fun getContactById(contactId: Int): Contact?

    @Query("UPDATE contacts SET name = :name, phone = :phone, relationship = :relationship WHERE id = :id")
    suspend fun updateContact(id: Int, name: String, phone: String, relationship: String)

    @Query("SELECT * FROM contacts WHERE smsAlerts = 1")
    suspend fun getContactsWithSmsAlerts(): List<Contact>
}

